'use strict';
(function initMobileMenu() {
const btn = document.getElementById('hamburger-btn');
const menu = document.getElementById('mobile-menu');
if (!btn || !menu) return;
btn.addEventListener('click', function () {
const isOpen = btn.getAttribute('aria-expanded') === 'true';
btn.setAttribute('aria-expanded', String(!isOpen));
menu.setAttribute('aria-hidden', String(isOpen));
menu.classList.toggle('is-open', !isOpen);
document.body.style.overflow = isOpen ? '' : 'hidden';
});
document.addEventListener('keydown', function (e) {
if (e.key === 'Escape' && menu.classList.contains('is-open')) {
btn.setAttribute('aria-expanded', 'false');
menu.setAttribute('aria-hidden', 'true');
menu.classList.remove('is-open');
document.body.style.overflow = '';
btn.focus();
}
});
document.addEventListener('click', function (e) {
if (menu.classList.contains('is-open') &&
!menu.contains(e.target) &&
!btn.contains(e.target)) {
btn.setAttribute('aria-expanded', 'false');
menu.setAttribute('aria-hidden', 'true');
menu.classList.remove('is-open');
document.body.style.overflow = '';
}
});
window.addEventListener('resize', function () {
if (window.innerWidth >= 900 && menu.classList.contains('is-open')) {
btn.setAttribute('aria-expanded', 'false');
menu.setAttribute('aria-hidden', 'true');
menu.classList.remove('is-open');
document.body.style.overflow = '';
}
});
}());
(function initSmoothScroll() {
document.addEventListener('click', function (e) {
const link = e.target.closest('a[href^="#"]');
if (!link) return;
const targetId = link.getAttribute('href').slice(1);
if (!targetId) return;
const target = document.getElementById(targetId);
if (!target) return;
e.preventDefault();
target.scrollIntoView({ behavior: 'smooth', block: 'start' });
target.focus({ preventScroll: true });
});
}());
(function initFaqAccordion() {
const faqItems = document.querySelectorAll('.faq__item');
faqItems.forEach(function (item) {
const btn = item.querySelector('.faq__q');
if (!btn) return;
btn.addEventListener('click', function () {
const isOpen = item.classList.contains('is-open');
faqItems.forEach(function (other) {
if (other !== item) {
other.classList.remove('is-open');
const otherBtn = other.querySelector('.faq__q');
if (otherBtn) otherBtn.setAttribute('aria-expanded', 'false');
}
});
item.classList.toggle('is-open', !isOpen);
btn.setAttribute('aria-expanded', String(!isOpen));
});
});
}());
(function initLightbox() {
const lightbox = document.getElementById('lightbox');
if (!lightbox) return;
const lightboxImg = lightbox.querySelector('.lightbox__img');
const lightboxClose = lightbox.querySelector('.lightbox__close');
const galleryItems = document.querySelectorAll('.gallery__item[data-src]');
if (!galleryItems.length) return;
function openLightbox(src, alt) {
if (!lightboxImg) return;
lightboxImg.src = src;
lightboxImg.alt = alt || '';
lightbox.classList.add('is-open');
lightbox.setAttribute('aria-hidden', 'false');
document.body.style.overflow = 'hidden';
if (lightboxClose) lightboxClose.focus();
}
function closeLightbox() {
lightbox.classList.remove('is-open');
lightbox.setAttribute('aria-hidden', 'true');
document.body.style.overflow = '';
}
galleryItems.forEach(function (item) {
item.addEventListener('click', function () {
openLightbox(item.dataset.src, item.dataset.alt || '');
});
item.addEventListener('keydown', function (e) {
if (e.key === 'Enter' || e.key === ' ') {
e.preventDefault();
openLightbox(item.dataset.src, item.dataset.alt || '');
}
});
});
if (lightboxClose) {
lightboxClose.addEventListener('click', closeLightbox);
}
lightbox.addEventListener('click', function (e) {
if (e.target === lightbox) closeLightbox();
});
document.addEventListener('keydown', function (e) {
if (e.key === 'Escape' && lightbox.classList.contains('is-open')) {
closeLightbox();
}
});
}());
(function initHeaderScroll() {
const header = document.getElementById('site-header');
if (!header) return;
const observer = new IntersectionObserver(
function (entries) {
header.classList.toggle('header--scrolled', !entries[0].isIntersecting);
},
{ threshold: 0, rootMargin: '-1px 0px 0px 0px' }
);
const sentinel = document.createElement('div');
sentinel.style.cssText = 'position:absolute;top:0;left:0;width:1px;height:1px;pointer-events:none';
document.body.prepend(sentinel);
observer.observe(sentinel);
}());